def resolvePath(current_path: str, target_path: str, symlinks: dict):

    def is_absolute_path(path):
        return path and path[0] == "/"

    cur = []
    operations = [x for x in target_path.split("/") if x]
    if not is_absolute_path(target_path):
        cur = [x for x in current_path.split("/") if x]

    def resolve_symlink(cur):
        x = "/" + "/".join(cur)
        visited = set([x])
        while x in symlinks:
            y = symlinks[x]
            if y in visited:
                raise ValueError("cycle")
            visited.add(y)
            x = y
        return [p for p in x.split("/") if p]

    for op in operations:
        if op == ".":
            continue
        elif op == "..":
            if cur:
                cur.pop()
        else:
            cur.append(op)

        try:
            cur = resolve_symlink(cur)
        except ValueError:
            return "CYCLE_DETECTED"

    return "/" + "/".join(cur)

